'use client';

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Calendar } from '@/components/ui/calendar';
import { ChartContainer, ChartTooltip, ChartTooltipContent } from '@/components/ui/chart';
import { doseHistory } from '@/lib/data';
import { CheckCircle2, AlertCircle, XCircle } from 'lucide-react';
import { format } from 'date-fns';
import { es } from 'date-fns/locale';
import { PieChart, Pie, Cell, Tooltip } from 'recharts';
import { useMemo } from 'react';

export default function HistoryPage() {
  const adherenceData = useMemo(() => {
    const taken = doseHistory.filter((d) => d.status === 'taken').length;
    const missed = doseHistory.length - taken;
    const adherence = (taken / doseHistory.length) * 100;
    return {
      percentage: Math.round(adherence),
      chartData: [
        { name: 'Tomada', value: taken, fill: 'hsl(var(--primary))' },
        { name: 'Perdida', value: missed, fill: 'hsl(var(--destructive))' },
      ],
    };
  }, []);

  const takenDays = useMemo(() => doseHistory.filter((d) => d.status === 'taken').map((d) => d.date), []);
  const missedDays = useMemo(() => doseHistory.filter((d) => d.status === 'missed').map((d) => d.date), []);
  
  const recentDoses = doseHistory.slice(0, 7);

  return (
    <div className="grid gap-6 md:grid-cols-2">
      <Card>
        <CardHeader>
          <CardTitle>Tu Adherencia</CardTitle>
          <CardDescription>Basado en los últimos 90 días.</CardDescription>
        </CardHeader>
        <CardContent className="flex items-center justify-center">
            <div className="relative h-48 w-48">
                <ChartContainer config={{}} className="absolute inset-0">
                    <PieChart>
                    <Tooltip cursor={false} content={<ChartTooltipContent hideLabel />} />
                    <Pie
                        data={adherenceData.chartData}
                        dataKey="value"
                        nameKey="name"
                        innerRadius={60}
                        strokeWidth={5}
                    >
                        {adherenceData.chartData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.fill} />
                        ))}
                    </Pie>
                    </PieChart>
                </ChartContainer>
                <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <span className="text-4xl font-bold">{adherenceData.percentage}%</span>
                    <span className="text-sm text-muted-foreground">Adherencia</span>
                </div>
            </div>
        </CardContent>
      </Card>
      
      <Card className="flex flex-col">
        <CardHeader>
          <CardTitle>Calendario Mensual</CardTitle>
        </CardHeader>
        <CardContent className="flex-grow flex justify-center items-center">
          <Calendar
            mode="single"
            modifiers={{
              taken: takenDays,
              missed: missedDays,
            }}
            modifiersClassNames={{
              taken: 'bg-primary/20 text-primary-foreground rounded-full',
              missed: 'bg-destructive/20 text-destructive-foreground rounded-full',
            }}
            className="p-0"
            locale={es}
          />
        </CardContent>
      </Card>
      
      <Card className="md:col-span-2">
        <CardHeader>
          <CardTitle>Registro de Dosis Recientes</CardTitle>
        </CardHeader>
        <CardContent>
          <ul className="space-y-4">
            {recentDoses.map((dose) => (
              <li key={dose.date.toString()} className="flex items-center">
                {dose.status === 'taken' ? (
                  <CheckCircle2 className="h-5 w-5 text-green-500" />
                ) : (
                  <XCircle className="h-5 w-5 text-destructive" />
                )}
                <span className="ml-3 capitalize">
                  {format(dose.date, "eeee, dd 'de' MMMM", { locale: es })}
                </span>
                <span
                  className={`ml-auto text-sm font-medium ${
                    dose.status === 'taken' ? 'text-green-600' : 'text-destructive'
                  }`}
                >
                  {dose.status === 'taken' ? 'Dosis tomada' : 'Dosis perdida'}
                </span>
              </li>
            ))}
          </ul>
        </CardContent>
      </Card>
    </div>
  );
}
